class MultiServerManager:
    """Manage multiple server instances for load distribution"""
    
    def __init__(self, base_port=50051, num_servers=4, workers_per_server=50):
        self.base_port = base_port
        self.num_servers = num_servers
        self.workers_per_server = workers_per_server
        self.servers = []
    
    def start_all(self):
        """Start multiple server instances"""
        for i in range(self.num_servers):
            port = self.base_port + i
            server = create_high_performance_server(port, self.workers_per_server)
            server.start()
            self.servers.append(server)
            print(f"Server {i+1} started on port {port}")
        
        print(f"\nTotal servers: {self.num_servers}")
        print(f"Workers per server: {self.workers_per_server}")
        print(f"Total capacity: {self.num_servers * self.workers_per_server} concurrent workers")
    
    def wait_for_termination(self):
        """Wait for all servers to terminate"""
        try:
            while True:
                time.sleep(86400)
        except KeyboardInterrupt:
            self.stop_all()
    
    def stop_all(self):
        """Stop all server instances"""
        for i, server in enumerate(self.servers):
            print(f"Stopping server {i+1}...")
            server.stop(0)


